/*
 * Raaka-Tu -- C port for OS-9 Level 2
 * Ported from the annotated 6809 disassembly (raaka-tu.asm)
 *
 * All game data lives in gamedata.c (generated by extract_data.py).
 * This file implements the parser, VM, and game loop.
 */

#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>
#include <string.h>

typedef unsigned char  byte;
typedef unsigned short word;

/* ---- game data arrays (from gamedata.c) --------------------------------- */
extern byte chartab[];       /* 40-byte base-40 char translation table       */
extern byte rand_seed[];     /* [0]=multivb, [1..8]=LFSR seed                */
extern byte msg_qverb[];     /* "?VERB?"   plain-ASCII length-prefixed string */
extern byte msg_qwhat[];     /* "?WHAT?"                                     */
extern byte msg_qwhich[];    /* "?WHICH?"                                    */
extern byte msg_qphrase[];   /* "?PHRASE?"                                   */
extern byte phrase_list[];   /* phrase syntax table (raw 5-byte entries)     */
extern byte room_data[];     /* room descriptions & scripts                  */
extern byte obj_data[];      /* object data                                  */
extern byte cmd_data[];      /* general command scripts                      */
extern byte ccmd_data[];     /* common command scripts                       */
extern byte vocab_data[];    /* vocabulary (verbs, nouns, adjs, preps)       */
extern byte prep_data[];     /* preposition list for phrase matching          */

/* ---- list navigation ---------------------------------------------------- */
/*
 * Each "list" is: [tag][len1 {len2}][content...]
 * If len1 bit7 clear: 1-byte length.  If set: 2-byte length ((len1&$7F)<<8 | len2).
 * len gives the number of bytes that FOLLOW the length field(s).
 *
 * list_end_from_len(p)  -- p points at the length byte; returns end pointer,
 *                          sets *content to the first content byte.
 * list_open(p)          -- p points at the tag byte; skips tag+len, returns end.
 * list_skip(p)          -- p points at the length byte (no tag); returns end.
 */

static byte *list_end_from_len(byte *p, byte **content)
{
    word len;
    if (*p & 0x80) {
        len = (word)((*p & 0x7F) << 8) | *(p+1);
        *content = p + 2;
    } else {
        len = *p;
        *content = p + 1;
    }
    return *content + len;
}

/* p points to the tag byte; skip tag+len, set *content_out, return end */
static byte *list_open(byte *p, byte **content_out)
{
    byte *q = p + 1;          /* skip tag */
    return list_end_from_len(q, content_out);
}

/* p points to the length byte (no tag); set *content_out, return end */
static byte *list_skip(byte *p, byte **content_out)
{
    return list_end_from_len(p, content_out);
}

/* Search through a sequence of items (p..list_end) for one whose tag==tag.
 * Each item is [tag][len...][content].
 * Returns pointer to the LENGTH PREFIX byte of the matching item (so callers
 * can pass it directly to print_packed or list_end_from_len).
 * Sets *end_out to the end of the matching item's content.
 * Returns NULL if not found. */
static byte *list_find_tag(byte *p, byte *list_end, byte tag, byte **end_out)
{
    while (p < list_end) {
        byte *content, *sub_end;
        byte sub_tag = *p;
        sub_end = list_open(p, &content);
        if (sub_tag == tag) {
            if (end_out) *end_out = sub_end;
            return p + 1;   /* pointer to the length prefix byte */
        }
        p = sub_end;
    }
    return NULL;
}

/* ---- game state --------------------------------------------------------- */

static byte  g_cur_room;          /* current room number                      */
static byte *g_cur_room_data;     /* pointer to room item content             */
static byte *g_cur_room_end;      /* end of room item content                 */

static byte  g_player_room;       /* player object number = 0x1D              */

static byte  g_var_obj_num;
static byte *g_var_obj_data;
static byte *g_var_obj_end;

static byte  g_noun1_num;
static byte *g_noun1_data;
static byte *g_noun1_end;
static byte  g_noun1_param;       /* loc byte of first noun                   */
static byte  g_noun1_typed;       /* vocab word# if a noun was typed for slot1 */

static byte  g_noun2_num;
static byte *g_noun2_data;
static byte *g_noun2_end;
static byte  g_noun2_param;
static byte  g_noun2_typed;       /* vocab word# if a noun was typed for slot2 */

static byte  g_phrase_form;       /* phrase form number                       */
static byte  g_active_obj;        /* active object (player object number)     */
static byte *g_active_obj_data;
static byte *g_active_obj_end;

static byte  g_verb;
static byte  g_prep;
static byte  g_prep_given;
